from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        # Remove surrounding quotes from object if present
        obj = obj.strip('"')
        # Normalise predicate strings
        p = pred.lower()
        if p == "birthdate":
            return f"{subj} was born on {obj}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {obj}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            return f"{subj} was {obj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            # status often like "Retired"
            return f"{subj} is {obj.lower()}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            return f"{subj} flew on {obj}"
        if p == "timeinspace":
            return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            return f"{obj} operated {subj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # Build a flat list of clause strings in the order of input triples
    clauses = [phrase(t.subject, t.predicate, t.object) for t in triples]

    # Join clauses into a single fluent sentence
    if not clauses:
        return ""
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

    return sentence

# EVOLVE-BLOCK-END
